(window.webpackJsonp=window.webpackJsonp||[]).push([[28],{344:function(n,t,v){"use strict";v.r(t);var _=v(7),a=Object(_.a)({},(function(){var n=this,t=n._self._c;return t("ContentSlotsDistributor",{attrs:{"slot-key":n.$parent.slotKey}},[t("div",{staticClass:"center-container"},[t("p",[t("img",{attrs:{src:"https://www.notion.so/image/https%3A%2F%2Fs3-us-west-2.amazonaws.com%2Fsecure.notion-static.com%2Fbb41c424-00a3-498c-bc1e-ca257ca8468b%2Fshangyue.png?table=block&id=16bc86ce-d776-46ef-9560-4c758f0a2d6e&spaceId=6f061d15-8f2e-42d0-a148-068fb412b305&width=600&userId=5191ad45-3310-4476-a47f-6c90dded5c8a&cache=v2",alt:""}})])]),t("br"),n._v(" "),t("p",[n._v("我认为补充深度的方法是培养主题探索的习惯。正如“鸡尾酒效应”，人只有在特定主题下才能关注到那些平时接触不到的信息。所以，我们平时就必须大量地进行主题探索，提前做足准备。这样，才能在遇到问题时产生强烈并且有深度的思考。\n"),n._v(" "),t("br")]),n._v(" "),t("p",[n._v("一开始面对这个疑问时，很多人会说，可能是平时积累不够，看得书不够、事情做得不够、修炼得不够。只要你坚持下来，随年龄和智慧的增长，思考也会慢慢有深度。\n"),t("br")]),n._v(" "),t("p",[n._v("这话听着正确，可总少了一些可行动的方向，就像投资里永恒的真理——“低买高卖”。\n"),t("br")]),n._v(" "),t("p",[n._v("我试图回顾一下，思考这个行为来自于对过往经验的认知。似乎从上学开始，我们总是以记住知识为主。而学校也基本是这么一个画风：语文背课文，数学背公式，英语背单词...... 我们在学习一门课的时候，总是在记住某个知识或者某个问题的答案，而很少去思考问题本身。所以，在“思考”的认知上，过往经验通常是言行不一的：思考很重要，但很少去思考。\n"),t("br")]),n._v(" "),t("p",[n._v("这样言行不一的后果就是，进入社会后，我们很容易遭受欺骗：比如我们想了解经济到底如何了，大概率看到的是“整体稳中向好”的报道。正好没有思考的习惯，我们也甘愿觉得的确如此，都不会去求证一下到底怎么就“稳中向好”了。\n"),t("br")]),n._v(" "),t("p",[n._v("2004 年，全球最大电脑制造商戴尔爆出了很多丑闻和经营性难题。时任 CEO 的罗斯林是一位具有长期战略眼光的领导人。但在这个事件中，人们把戴尔发生的所有负面事件都和罗斯林本人联系起来，认为以上的种种结果都是他一人造成的。领导能力不行，那么理应下台。\n"),t("br")]),n._v(" "),t("p",[n._v("这是一种简单关联的思维，它暗含一个假设：一家公司的成功与否，与其领导者息息相关。所以经营不善的戴尔，必然是因为罗斯林的领导能力不行。但这只是一种毫无事实根据的快思考，甚至提出观点的人们都不想去验证，是否真的有证据能证明这个假设。他们急着对罗斯林破口大骂，认为破除戴尔困局的唯一结论就是让罗斯林滚蛋。\n"),t("br")]),n._v(" "),t("p",[n._v("好在戴尔的创始人并没有这么做，他顶住了舆论的压力，并且给与了罗斯林信任、时间和帮助。结果没过几年，戴尔又重现了它的辉煌。\n"),t("br")]),n._v(" "),t("p",[n._v("回顾这个困局，戴尔的创始人在出现风波时，就第一时间集中注意力，去寻找那些不知道或是缺失的信息，为此更是重资成立了专项调研小组。结果发现无论是丑闻还是经营性问题，都有足够的证据证明与罗斯林无关。小组的结论是，当下最优策略是协助罗斯林去解决这些戴尔积累已久的问题。这其实就是一种带有行动基因的慢思考，它是基于事实信息和验证，最后才做决策的思考方式。\n"),t("br")]),n._v(" "),t("p",[n._v("所以，当我们自然快速地得出一个结论时，心中一定要有所警惕：是不是过去的刻板印象发挥了作用？自己有没有深入地去研究、去收集事实信息并加以验证？\n"),t("br")]),n._v(" "),t("p",[n._v("我们也可以用几个问题来质疑直觉：")]),n._v(" "),t("ul",[t("li",[n._v("直觉的结论是什么？")]),n._v(" "),t("li",[n._v("有什么事实信息支撑着这个结论？")]),n._v(" "),t("li",[n._v("直觉的结论与事实之间的联系是合理的吗？\n"),t("br")])]),n._v(" "),t("p",[n._v("这些问题会让人做决定的心立即冷静下来——至少搞清楚问题，才不会拍脑袋做决定。而思索这些问题，并且收集证据的过程也就是我们真正主动思考的过程。当我们投入时间，认真去甄别信息、验证信息，“思考的深度”也就开始出现了。\n"),t("br")]),n._v(" "),t("p",[n._v("最后，以一个求职掉进误区的例子来结尾：我们找工作时，总想着一份简历投递多个岗位。一旦没有获得面试邀请，就会下意识地认为是因为简历不行或者对方根本不诚心招人。但实际上，招聘需求写出来就是为团队找到匹配的人。所以，如果简历与招聘需求的匹配率越高，那么面试邀请率自然也就越高。但从简历主动匹配用人要求的过程，需要我们在招聘市场上花大量时间进行信息收集和验证。而很多人却“懒”得这么做——他们往往拥有僵固的思维，认为直接在简历上修改更有效些，十分可惜。")])])}),[],!1,null,null,null);t.default=a.exports}}]);